import React from 'react';
import Icon from '../../../components/AppIcon';

const CostBreakdown = ({ bookingDetails }) => {
  const formatPrice = (price) => {
    return price?.toFixed(2);
  };

  // Calculate new commission structure
  const platformFee = bookingDetails?.equipmentTotal * 0.12; // 12% platform commission
  const paymentFee = (bookingDetails?.equipmentTotal * 0.015) + 0.25; // 1.5% + 0.25 EUR payment fees
  const totalFees = platformFee + paymentFee;
  const newTotalAmount = bookingDetails?.equipmentTotal + totalFees;

  return (
    <div className="space-y-3">
      {/* Equipment Price */}
      <div className="flex justify-between items-center py-2">
        <div className="flex items-center gap-2">
          <Icon name="Package" size={18} className="text-muted-foreground" />
          <span className="text-sm text-foreground">
            Location equipement ({bookingDetails?.rentalDays} jour{bookingDetails?.rentalDays > 1 ? 's' : ''})
          </span>
        </div>
        <span className="font-medium text-foreground">
          {formatPrice(bookingDetails?.equipmentTotal)} EUR
        </span>
      </div>

      {/* Platform Commission */}
      <div className="flex justify-between items-center py-2">
        <div className="flex items-center gap-2">
          <Icon name="Percent" size={18} className="text-muted-foreground" />
          <span className="text-sm text-muted-foreground">
            Commission plateforme (12%)
          </span>
        </div>
        <span className="text-sm text-muted-foreground">
          {formatPrice(platformFee)} EUR
        </span>
      </div>

      {/* Payment Fees */}
      <div className="flex justify-between items-center py-2">
        <div className="flex items-center gap-2">
          <Icon name="CreditCard" size={18} className="text-muted-foreground" />
          <span className="text-sm text-muted-foreground">
            Frais de paiement (1,5% + 0,25 EUR)
          </span>
        </div>
        <span className="text-sm text-muted-foreground">
          {formatPrice(paymentFee)} EUR
        </span>
      </div>

      {/* Divider */}
      <div className="border-t border-border my-3" />

      {/* Total to Pay */}
      <div className="flex justify-between items-center py-2">
        <span className="text-lg font-semibold text-foreground">
          Total a payer
        </span>
        <span className="text-xl font-bold text-primary">
          {formatPrice(newTotalAmount)} EUR
        </span>
      </div>

    </div>
  );
};

export default CostBreakdown;
